/// Protobuf-generated types — see `proto/abutown.proto` for the schema.
/// Generated by `build.rs` via `prost-build`; output lands in `OUT_DIR`.
/// Module name matches the proto `package abutown.v1` namespace.
pub mod v1 {
    include!(concat!(env!("OUT_DIR"), "/abutown.v1.rs"));
}

use serde::{Deserialize, Serialize};

pub const PROTOCOL_VERSION: u16 = 1;

